UPDATE UB_MENTEE_BOARD
SET board_read_count = board_read_count + 1
WHERE menteeBoard_number = #{menteeBoardNumber}

UPDATE UB_MENTEE_BOARD
SET board_title = #{boardTitle}, board_content = #{boardContent}

WHERE menteeBoard_number = #{menteeBoardNumber}

mapper.select:

SELECT * FROM (
	SELECT ROWNUM AS rnum, subquery.*
	FROM (
		SELECT m.member_number, m.member_id, b.menteeBoard_number, b.board_title, 
			b.board_content, b.board_date, b.board_read_count
		FROM tbl_member m JOIN UB_MENTEE_BOARD b
		ON m.member_number = b.member_number
		ORDER BY b.board_date DESC
	) subquery
) WHERE rnum BETWEEN #{startRow} AND #{endRow}
